import React from 'react';
import { ListGroup, Button } from 'react-bootstrap';

const FilterSidebar = ({ categories = [], selectedCategory, setSelectedCategory, handleClearFilters }) => {
  
  // Lista de categorías incluyendo "Todas"
  const allCategories = [{ id: 0, name: 'Todas' }, ...categories];

  return (
    <>
      <h6 className="text-sm font-semibold uppercase text-gray-500 mb-2">Categorías</h6>
      
      <ListGroup variant="flush" className="p-0 border-0">
        {allCategories.map((category) => ( 
          // CRÍTICO: Usamos clases de Tailwind para el estilo y la interactividad
          <ListGroup.Item 
            key={category.id} 
            action 
            onClick={() => setSelectedCategory(category.name === 'Todas' ? '' : category.name)}
            // Clases de Tailwind para ListGroup.Item
            className={`
              cursor-pointer 
              py-2 px-3 mb-1 
              rounded-lg 
              border-0
              // Fondo transparente y color de texto por defecto
              bg-transparent text-gray-700
              // Hover: Fondo gris claro y texto primario
              hover:bg-gray-100 hover:text-gray-900 
              transition-colors duration-200
              ${(category.name === 'Todas' && !selectedCategory) || (category.name === selectedCategory) 
                ? 'bg-[var(--brand-dark)] text-white hover:bg-[var(--brand-dark)] hover:text-white' 
                : ''
              }
            `}
            // Se usa el valor de la categoría para 'active'
            active={(category.name === 'Todas' && !selectedCategory) || (category.name === selectedCategory)}
            style={{ 
                // CRÍTICO: Aseguramos que el botón "Todas" (o la categoría seleccionada) use el color de fondo oscuro
                backgroundColor: ((category.name === 'Todas' && !selectedCategory) || (category.name === selectedCategory)) 
                    ? 'var(--brand-dark)' 
                    : 'transparent',
                color: ((category.name === 'Todas' && !selectedCategory) || (category.name === selectedCategory)) 
                    ? 'var(--text-on-dark)' 
                    : 'var(--text-primary)',
            }}
          >
            {category.name}
          </ListGroup.Item>
        ))}
      </ListGroup>
      
      {/* Botón de limpiar filtros con estilo moderno */}
      <Button 
        variant="outline-secondary" 
        className="w-full mt-4 text-sm font-semibold rounded-lg border-gray-300 text-gray-600 hover:bg-gray-100 transition-colors" 
        onClick={handleClearFilters}
        style={{ borderWidth: '1px', borderColor: '#CBD5E1' }}
      >
        Limpiar Filtros
      </Button>
    </>
  );
};

export default FilterSidebar;
